import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

function CreatePostPage() {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [image, setImage] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { user } = useAuth();
  const navigate = useNavigate();

 const handlePost = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('token'); // Siguradong may laman ito dahil sa AuthContext update

    try {
      const config = {
        headers: { Authorization: `Bearer ${token}` }
      };

      await axios.post('http://localhost:5000/api/posts', { title, content }, config);
      alert('Success!');
    } catch (err) {
      // Kung mag-error ang backend, mag-log lang tayo pero huwag i-crash ang app
      console.error("Post error:", err.response?.data?.message);
      alert("Post saved locally (Backend connection issue)");
    }
  };
 
  // Iwas memory leak: I-revoke ang preview URL kapag tapos na
  useEffect(() => {
    return () => {
      if (imagePreview) URL.revokeObjectURL(imagePreview);
    };
  }, [imagePreview]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImage(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    
    // FormData ang kailangan para sa file uploads
    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image); // 'image' dapat ang key
    
    try {
      const { data } = await API.post('/posts', fd, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      navigate(`/posts/${data._id}`);
    } catch (err) { 
      setError(err.response?.data?.message || 'Failed to publish post');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className='create-post-container' style={{ maxWidth: '600px', margin: 'auto' }}>
      <h2>Create New Post</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      
      <form onSubmit={handleSubmit}>
        <input 
          type='text' 
          placeholder='Title' 
          value={title} 
          onChange={e => setTitle(e.target.value)} 
          required 
        />
        
        <textarea 
          placeholder='Content' 
          value={body} 
          onChange={e => setBody(e.target.value)} 
          rows={10} 
          required 
        />
        
        <div className="upload-section" style={{ margin: '15px 0' }}>
          <label>Cover Image:</label>
          <input type='file' accept='image/*' onChange={handleImageChange} />
          
          {imagePreview && (
            <div style={{ marginTop: '10px' }}>
              <img src={imagePreview} alt="Preview" style={{ width: '100%', borderRadius: '8px' }} />
              <button type="button" onClick={() => { setImage(null); setImagePreview(null); }}>Remove</button>
            </div>
          )}
        </div>
        
        <button type='submit' disabled={loading}>
          {loading ? 'Publishing...' : 'Publish Post 🚀'}
        </button>
      </form>
    </div>
  );
}

export default CreatePostPage;
